import Image from 'next/image'
import { cn } from '@/lib/utils'

interface PhotoCardProps {
    src: string
    alt: string
    width: number
    height: number
    className?: string
}

const PhotoCard = ({ src, alt, width, height, className }: PhotoCardProps) => {
    return (
        <Image
            src={src}
            alt={alt}
            width={width}
            height={height}
            className={cn('object-cover rounded-lg', className)}
        />
    )
}

export default PhotoCard